"""CRUD routes — generated by doql."""
from fastapi import APIRouter, Depends, HTTPException
from sqlalchemy.orm import Session
from database import get_db
import models
import schemas

router = APIRouter(prefix='/api/v1')

# ── Product ──

@router.get("/products", response_model=list[schemas.ProductResponse])
def list_products(skip: int = 0, limit: int = 100, db: Session = Depends(get_db)):
    return db.query(models.Product).offset(skip).limit(limit).all()

@router.get("/products/{item_id}", response_model=schemas.ProductResponse)
def get_product(item_id: str, db: Session = Depends(get_db)):
    obj = db.query(models.Product).filter(models.Product.id == item_id).first()
    if not obj:
        raise HTTPException(404, "Product not found")
    return obj

@router.post("/products", response_model=schemas.ProductResponse, status_code=201)
def create_product(data: schemas.ProductCreate, db: Session = Depends(get_db)):
    import uuid as _uuid
    payload = data.model_dump()
    payload.setdefault('id', str(_uuid.uuid4()))
    obj = models.Product(**payload)
    db.add(obj)
    db.commit()
    db.refresh(obj)
    return obj

@router.patch("/products/{item_id}", response_model=schemas.ProductResponse)
def update_product(item_id: str, data: schemas.ProductUpdate, db: Session = Depends(get_db)):
    obj = db.query(models.Product).filter(models.Product.id == item_id).first()
    if not obj:
        raise HTTPException(404, "Product not found")
    for key, val in data.model_dump(exclude_unset=True).items():
        setattr(obj, key, val)
    db.commit()
    db.refresh(obj)
    return obj

@router.delete("/products/{item_id}", status_code=204)
def delete_product(item_id: str, db: Session = Depends(get_db)):
    obj = db.query(models.Product).filter(models.Product.id == item_id).first()
    if not obj:
        raise HTTPException(404, "Product not found")
    db.delete(obj)
    db.commit()

